-- 3. products/modules (id=3) - 六大模块详解
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"id":"supplier","icon":"warehouse","title":"Supplier Management","sub":"Supplier Management","desc":"Don''t fight fires after problems arise — get warned before they happen. Automatically track each supplier''s on-time rate, quality pass rate, and price trends. Alerts you to switch to alternatives before performance deteriorates.","tags":["On-Time Tracking","Quality Monitoring","Price Alerts","Multi-Source Backup"]},{"id":"procurement","icon":"clipboard","title":"Smart Procurement","sub":"Procurement","desc":"Stop guessing when to restock. AI demand forecasting + TCO full-chain price comparison + automated order tracking. PO cycle shrinks from 3–5 days to under 1 day.","tags":["AI Demand Forecast","TCO Comparison","PO Automation","Delivery Alerts"]},{"id":"wms","icon":"package","title":"Warehouse Management (WMS)","sub":"Warehouse","desc":"Less inventory isn''t always better — the cost of a stockout far exceeds warehousing fees. Dynamic safety stock models find your optimal level. Turnover days drop from 90 to 55.","tags":["Dynamic Safety Stock","Wave Picking","Expiry Management","FBA Integration"]},{"id":"oms","icon":"list","title":"Order Fulfillment (OMS)","sub":"Order Management","desc":"Orders come in — the system automatically picks the cheapest and fastest way to ship. Multi-channel intake, intelligent split/merge, SLA timeout alerts — no need to stare at screens all day.","tags":["Multi-Channel Intake","Smart Routing","Auto Split/Merge","SLA Alerts"]},{"id":"tms","icon":"truck","title":"Global Logistics (TMS)","sub":"Transportation","desc":"Where''s the shipment? Will it be delayed? — No need to call the freight forwarder. Real-time tracking + ETA prediction + automatic anomaly alerts. Know before it becomes a problem.","tags":["Real-Time Tracking","ETA Prediction","Multimodal","Anomaly Alerts"]},{"id":"customs","icon":"file-text","title":"Cross-Border Customs","sub":"Customs","desc":"Overpaid duties without knowing? Fined for wrong HS codes? AI auto-classification + duty optimization + compliance risk control. Declaration error rate drops from 5–10% to under 2%.","tags":["HS Smart Classification","Duty Optimization","AI Document Audit","Compliance Alerts"]}]' WHERE id = 3;

-- ============================================================
-- 4. products/beyond-core (id=4) - 增值模块
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"icon":"shuffle","title":"Distribution & Reseller Network","sub":"Distribution Network","desc":"Good products lack channels, good channels lack products — both sides still rely on WeChat messages and manual reconciliation, with revenue-sharing disputes every week. Brands list products in the distribution pool; resellers select products with zero inventory; orders complete with automatic revenue sharing. One person manages 100+ distributors effortlessly, with real-time cross-territory sales monitoring.","tags":["Supplier & Reseller Onboarding","Distribution Product Selection","Auto Revenue Sharing","Cross-Territory Monitoring"]},{"icon":"chart","title":"Analytics & Reporting Center","sub":"Analytics","desc":"Data scattered across procurement, warehousing, and logistics systems — to get the full picture, you have to wait for each department to pull Excel sheets. By the time the report arrives, the problem may have been brewing for three days. All data consolidated into a single real-time dashboard. Just type \\"which SKU is losing margin?\\" and AI pinpoints the cause. No waiting for reports, no meetings required.","tags":["Real-Time Dashboard","Natural Language Query","Cost Attribution","Alert Center"]}]' WHERE id = 4;

-- ============================================================
-- 5. products/ai-everywhere (id=5) - AI 赋能体系
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"icon":"cpu","title":"AI Copilot","sub":"Natural Language · Business Data","desc":"Connects directly to your business database. Ask in natural language — \\"Which of my shipments will be affected by the US West Coast port strike?\\" — get the affected list and recommendations in seconds."},{"icon":"trending-up","title":"Demand Forecasting Engine","sub":"12+ Dimensions · Weekly Rolling","desc":"Integrates historical sales, search trends, seasonality, competitor pricing, and more. Rolling weekly forecasts by SKU × region — staying ahead of inventory consumption."},{"icon":"alert-triangle","title":"Risk Detection Engine","sub":"Trend Tracking · Early Signal","desc":"Continuously tracks subtle trending shifts in delivery times, quality, and pricing. Signals before they escalate into incidents — no need to wait for fixed-threshold alarms. It spots trouble before you do."},{"icon":"dollar-sign","title":"TCO Optimization Engine","sub":"Total Cost · Multi-Route Compare","desc":"Quotes show unit price; AI calculates the full picture — duties, freight, warehousing, working capital all factored in. The same batch can vary 15% in total cost across different routes. The system pinpoints the best option."},{"icon":"sliders","title":"Scheduling Simulation Engine","sub":"What-If Simulation · 12-Week Preview","desc":"Input promotion plans, route changes, and supplier lead times. The system runs simulations and shows you where the bottlenecks will be. Preview 12 weeks ahead, leaving ample time to adjust."},{"icon":"target","title":"Decision Recommendation Cards","sub":"Multi-Option · Impact Analysis","desc":"Every alert comes with 2–3 actionable options, each with cost, timeline, and side effects clearly laid out — you just choose. No meetings required."}]' WHERE id = 5;

