-- 8. solutions/scenarios (id=8) - 四大场景
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"id":"procure","tag":"Cross-Border Procurement","tagClass":"tag-procure","title":"From Sourcing to PO Issuance — All Within the System","desc":"It''s not that you can''t find suppliers — it''s that you don''t know which ones are reliable or how tariffs might change. Multi-source comparison + tariff sandbox simulation + automated order tracking. PO cycle shrinks from 3–5 days to under 1 day.","items":["Multi-source sourcing with automatic supplier on-time & quality tracking","Tariff TCO sandbox simulation — full cost transparency behind every quote","Quick-response replenishment: demand signals drive procurement decisions directly"],"img":"https://images.unsplash.com/photo-1494412574643-ff11b0a5c1c3?auto=format&fit=crop&w=1400&q=85"},{"id":"overseas","tag":"Overseas Warehouse","tagClass":"tag-overseas","title":"Multi-Warehouse Inventory as One Unified View — AI Tells You Where to Stock and How Much","desc":"Domestic warehouses, overseas warehouses, FBA, bonded warehouses — a single unified inventory view with AI-driven dynamic stock allocation. Too much ties up capital; too little means stockouts. Find the optimal balance.","items":["Multi-warehouse network unified view — inventory levels at a glance","FBA smart replenishment recommendations to avoid stockouts and redundancy","End-to-end first-mile and last-mile tracking with proactive anomaly alerts"],"img":"https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&w=1400&q=85"},{"id":"dropship","tag":"Dropshipping","tagClass":"tag-dropship","title":"Test for Bestsellers with Zero Inventory — Stock Up Only After Validation","desc":"New product testing, long-tail SKUs, small-batch trial runs — not every product is worth stocking overseas upfront. Ship parcels directly from domestic warehouses to consumers, with automatic matching of the optimal customs declaration mode. Minimize trial-and-error costs.","items":["Small-parcel direct mail with automatic 9610/9710/9810 mode matching","End-to-end tracking — full transparency for end consumers","Test data feeds back to guide inventory stocking decisions"],"img":"https://images.unsplash.com/photo-1601584115197-04ecc0da31d7?auto=format&fit=crop&w=1400&q=85"},{"id":"distribution","tag":"Distribution Network","tagClass":"tag-distribution","title":"Smart Supplier-Reseller Matching, Automatic Revenue Sharing, No More Disputes","desc":"Those with good products lack channels; those with good channels lack products. Suppliers list in the distribution pool; resellers select products with zero inventory; orders complete with automatic proportional revenue sharing. One person manages 100+ distributors effortlessly.","items":["Two-sided matching — supply and demand intelligently paired","Auto revenue sharing upon order completion — goodbye manual reconciliation","Distribution tiering + cross-territory monitoring — channel秩序 under control"],"img":"https://images.unsplash.com/photo-1556761175-b413da4baf72?auto=format&fit=crop&w=1400&q=85"}]' WHERE id = 8;

