-- 9. solutions/fulfillment (id=9) - 四种履约通道
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"badge":"A","title":"FBA Fulfillment","sub":"Amazon Fulfillment","desc":"Goods stored in Amazon FBA warehouses, fully managed picking and delivery. Ideal for Prime-eligible products. The platform provides inventory visibility and replenishment decision support."},{"badge":"B","title":"Third-Party Overseas Warehouse","sub":"3PL Warehouse","desc":"Unified inventory fulfillment across multiple platforms, with the merchant managing last-mile delivery. The platform handles waybill creation, rate comparison, tracking, and POD returns."},{"badge":"C","title":"Direct Mail (FBS/FBM)","sub":"Direct Mail","desc":"International express shipped directly from domestic warehouses to overseas consumers. Ideal for small items, low-frequency orders, long-tail SKUs, and new product testing."},{"badge":"D","title":"Bonded Warehouse","sub":"Bonded Warehouse","desc":"Bulk import into domestic bonded warehouses; customs clearance and dispatch upon order. 1–3 day delivery, with per-unit logistics costs 30–40% lower than direct mail."}]' WHERE id = 9;

