-- 10. solutions/stages (id=10) - 成长阶段选型
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"icon":"seed","title":"Startup & Trial Phase","sub":"Monthly Orders < 2,000 · Many Scattered SKUs","desc":"Domestic warehouse direct mail + small-scale FBA testing. Validate real demand at minimal cost, then decide where to scale.","tags":["Direct Mail Primary","Small-Batch Testing","Demand Validation"]},{"icon":"rocket","title":"Growth & Expansion Phase","sub":"Monthly Orders 2,000–20,000 · Bestsellers Emerging","desc":"FBA for Prime delivery speed + overseas warehouse for cost efficiency. Dual-warehouse并行 with AI demand forecasting driving replenishment cadence.","tags":["FBA + Overseas Warehouse","Smart Replenishment","Stockout & Overstock Prevention"]},{"icon":"mountain","title":"Mature & Scale Phase","sub":"Monthly Orders > 20,000 · Multi-Region, Multi-Channel","desc":"Multi-country regional warehouses + multi-source supply + elastic routing. Build a resilient network with the control tower making globally optimal decisions.","tags":["Regional Warehouse Network","Multi-Source Procurement","Control Tower"]},{"icon":"import","title":"Importing? Prioritize Bonded Warehouse","sub":"IMPORT · Inbound Direction","desc":"If you''re selling overseas brand products to Chinese consumers, we recommend \\"bonded warehouse bulk stocking +清单核放 & consolidated declaration\\": bulk ship by sea into domestic bonded warehouses, clear customs and dispatch per order — 1–3 day ultra-fast delivery with per-unit logistics costs 30–40% lower than direct mail. Ideal for high-repurchase categories like powdered milk, cosmetics, and mother & baby products. For niche long-tail items, use 9610 direct mail for testing.","tags":["Bonded Warehouse Stocking","清单核放","9610 Direct Mail Testing"]}]' WHERE id = 10;

-- ============================================================
-- 11. solutions/perspectives (id=11) - 供应链观点
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"icon":"zap","title":"Don''t Over-Rely on FBA","desc":"FBA has speed advantages, but platform rules, storage fees, and account suspension risk are all outside your control. Keep core inventory in your own or third-party overseas warehouses and use FBA for Prime traffic — that keeps you in the driver''s seat."},{"icon":"scale","title":"Less Inventory Isn''t Always Better","desc":"Blindly cutting inventory trades stockouts for a prettier balance sheet. What you should really optimize is the balance between service level and holding cost — that''s exactly what dynamic safety stock models are designed for."},{"icon":"send","title":"The Value of Direct Mail Is Often Underestimated","desc":"Many dismiss direct mail as a low-end fallback, but it''s actually a low-cost way to test products: zero warehousing, fast listing, fast delisting. Test new products with direct mail first; once validated, ship by sea to stock up. This effectively minimizes trial-and-error costs."},{"icon":"shield","title":"Resilience Is Becoming as Important as Efficiency","desc":"For the past decade, supply chains pursued extreme efficiency — but a single disruption can wipe out all the gains. In the post-pandemic era, the ability to quickly reorganize amid shocks is becoming just as critical as efficiency."}]' WHERE id = 11;

