-- 16. why-us/copilot (id=16) - AI Copilot 展示
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"num":"01","phase":"PREDICT","title":"Demand Forecasting with 90%+ Accuracy","desc":"Integrates 12+ data dimensions — historical sales, search trends, seasonality, competitor pricing — producing rolling weekly forecasts at SKU × region granularity. Say goodbye to gut-feel stocking.","chat":[{"role":"user","text":"SKU-8892 inventory is running low — when should I restock?"},{"role":"ai","text":"On hand: 42 units. In transit: 200 units (ETA Jun 8). Recent 30-day avg daily consumption: 15 units. Dynamic safety stock: 60 units. ⚠️ Potential ~8-day stockout window detected. Recommend immediate emergency replenishment of 200 units, or transfer 120 units from Hangzhou warehouse (lower cost)."}]},{"num":"02","phase":"RESPOND","title":"From Days to Hours","desc":"Typhoon path ∩ your in-transit containers → auto-match affected shipments → push alternative plans → one-click switch. Anomaly response shrinks from the traditional 2–5 days to under 4 hours.","chat":[{"role":"user","text":"Is there a strike at the Port of Long Beach? Which of my shipments will be affected?"},{"role":"ai","text":"Confirmed: Long Beach port strike since May 26. You have 12 affected in-transit shipments: 3 already arrived awaiting unloading (demurrage ~$1,200/day), 5 arriving within 3 days. 🟡 Recommend rerouting those 5 to Oakland to avoid demurrage risk. Shall I generate the rerouting request draft?"}]},{"num":"03","phase":"DECIDE","title":"Not Just Alerts — Actionable Choices","desc":"The system doesn''t just sound alarms — it provides 2–3 recommended options with quantified impact: Option A switches to backup supplier at +8% cost; Option B uses air freight补货 at +15% cost but saves 20 days. You just choose.","chat":[{"role":"ai","text":"Detected: Supplier A delivery times continuously deteriorating (28 → 31 → 35 days). 📋 Option A: Switch to backup Supplier X, +8% cost, same lead time. 📋 Option B: Partial air freight补货, +15% cost, saves 20 days. 🟢 Recommend Option A. Shall I execute the PO change and notify both parties?"},{"role":"user","text":"Execute Option A."}]},{"num":"04","phase":"EXECUTE","title":"One-Click Dispatch, Full-Chain Auto-Execution","desc":"Once a decision is confirmed, PO changes, shipment rerouting, and inventory transfers are automatically dispatched to the corresponding systems — no cross-department email chains needed. Execution results feed back in real time; if deviations exceed thresholds, a secondary alert is automatically triggered.","chat":[{"role":"ai","text":"✅ PO-7742 switched to Supplier X, new delivery date Jun 18. ✅ Supplier A notified of suspension. ✅ Hangzhou warehouse transfer order created, ETA Jun 8. 📊 All changes synced to control tower. Deviations exceeding 5% will auto-trigger alerts."}]}]' WHERE id = 16;

