-- 17. why-us/difference (id=17) - 六大差异化优势
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"icon":"globe","title":"Built-In Global Intelligence Layer","sub":"Global Intelligence Layer","desc":"More than just process digitization — we layer real-time intelligence on top of your workflows: policies, tariffs, typhoons, and strikes are automatically linked to specific shipments. Proactive alerts, not reactive firefighting."},{"icon":"link","title":"Unified Data Foundation","sub":"Unified Data Foundation","desc":"Procurement, warehousing, logistics, orders, and customs all share the same master data. One SKU, one consistent ID across the entire chain. From PO to POD — traceable in one click, locatable in seconds."},{"icon":"trending-up","title":"Measurable Outcomes","sub":"Measurable Outcomes","desc":"No vague promises: procurement on-time rate ≥ 93%, inventory turnover ≤ 55 days, anomaly response ≤ 4 hours. Validate first, then scale. Demonstrable and trial-ready."},{"icon":"cpu","title":"AI Embedded Across the Full Chain","sub":"AI Everywhere","desc":"AI isn''t a standalone add-on — it lives at every decision point. Auto-compare quotes at PO issuance, auto-alert on low inventory, auto-suggest alternative routes when shipping lanes break — no manual trigger needed."},{"icon":"shield","title":"Resilient Supply Network","sub":"Resilient Network","desc":"Multi-source procurement + multi-hub logistics + elastic routing. Reorganize supply chains within hours when a single point fails. Don''t put all your eggs in one basket."},{"icon":"zap","title":"Rapid Deployment & Validation","sub":"Rapid Deployment","desc":"Modular design. Start with one scenario, see results within weeks, then expand. Not the typical 12-month heavyweight deployment."}]' WHERE id = 17;

