-- 24. pain-points/pain-points (id=34) - 八大痛点详解
-- ============================================================
UPDATE page_sections SET items_json_en = '[{"img":"https://images.unsplash.com/photo-1494412574643-ff11b0a5c1c3?auto=format&fit=crop&w=1200&q=80","num":"Geopolitical Shock","desc":"The Russia-Ukraine conflict, Suez Canal blockages, punitive tariffs — these are no longer black swans but frequent gray rhinos. A single route passing through a conflict zone faces immediate disruption.","items":["Multi-source procurement: 2–3 suppliers from different regions for each critical material, with automatic single-source risk detection","Elastic routing: 2+ alternatives pre-configured for each core lane, anomaly-triggered intelligent rerouting","Tariff sandbox: auto-fetch destination-country HS code rates at PO creation, multi-origin TCO comparison"],"title":"Geopolitical Conflict & Trade Protectionism"},{"img":"https://images.unsplash.com/photo-1526304640581-d334cdbbf45e?auto=format&fit=crop&w=1200&q=80","num":"Policy & FX Risk","desc":"Export control lists change overnight, exchange rates jump from 7.0 to 7.3 — annual contracts and monthly plans simply cannot keep pace with policy shifts.","items":["Policy intelligence center: auto-aggregate China + destination-country policy announcements, push by category/route","Multi-currency & FX hedging: real-time exposure dashboard, forward rate lock alerts","Scenario planning: three parameter templates — normal / deteriorating / extreme — one-click switching"],"title":"Uncertainty from Great-Power Competition"},{"img":"https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1200&q=80","num":"Demand Volatility","desc":"A category suddenly explodes in demand, a region imposes new certification rules — manually monitoring markets means either missing windows by reacting too slowly or piling up inventory from misjudgment. The bullwhip effect amplifies upstream.","items":["Demand sensing engine: ingests order volume, search trends, competitor pricing, outputs rolling forecasts","Dynamic safety stock: auto-calculated from volatility, lead time std dev, and target service levels","Quick-response replenishment: pre-configured rapid POs for high-frequency Class-A SKUs, placed within 24 hours"],"title":"Extreme Global Demand Volatility"},{"img":"https://images.unsplash.com/photo-1551288049-bebda4e38f71?auto=format&fit=crop&w=1200&q=80","num":"Data Silos","desc":"Weather, logistics, policy, and inventory data are scattered across carrier websites, customs systems, ERPs, and Excel — completely disconnected. When a hurricane approaches a destination port, you need to dig through 5 systems just to piece together the picture.","items":["Unified data foundation: procurement/WMS/TMS/orders share master data, eliminating fragmented records","Supply chain control tower: world map showing real-time in-transit, inventory, and PO progress","Event-driven alerts: typhoon path intersecting in-transit containers = auto-generated impacted shipment list"],"title":"Multi-Link Information Silos, No Global Visibility"},{"img":"https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&w=1200&q=80","num":"Supply–Demand Gap","desc":"Goods go unsold while buyers cannot find supply. Industrial clusters have capacity but no channels; overseas buyers have demand but cannot find reliable suppliers. Every additional intermediary layer adds 15–30% in information distortion and cost.","items":["Capacity sharing platform: register idle capacity, equipment specs, minimum batch sizes; match supply and demand","Industrial cluster digital catalog: photos + certifications + factory audit reports accessible online","Reverse demand matching: buyers post RFIs; system auto-routes to qualified suppliers"],"title":"Inefficient Supply–Demand Matching, Massive Resource Waste"},{"img":"https://images.unsplash.com/photo-1601584115197-04ecc0da31d7?auto=format&fit=crop&w=1200&q=80","num":"Cost & Speed","desc":"Cross-border involves 6–8 nodes, each introducing delays, markups, and error probability. Ocean freight quotes contain 20+ surcharges, making comparison nearly impossible. Average demand-to-warehouse lead time is 45–90 days — by then the market has already shifted.","items":["Smart routing engine: input origin + destination + volume, output total cost + transit time + carbon comparison","Global scheduling: simulate fulfillment bottlenecks 4–12 weeks ahead; pre-position inventory or delay arrivals","Cost transparency: quotes broken down to per-item rates; comparison no longer misled by seemingly cheap quotes"],"title":"High Cost, Slow Response, Lack of Resilience"},{"img":"https://images.unsplash.com/photo-1553413077-190dd305871c?auto=format&fit=crop&w=1200&q=80","num":"Concentration Risk","desc":"A single supplier accounts for 80%+ — a factory fire means 3 months of stockout for a core SKU. All shipments route through the US West Coast — a dockworker strike strands 200 containers with daily penalties in the tens of thousands.","items":["Distributed supply network: allocate supplier shares at 6:3:1, with regular rotation for trial supply","Multi-hub logistics: upgrade from single-country single-warehouse to multi-country regional warehouses, dispersing node risk","Stress testing: disruption simulation + risk exposure heatmap; proactively de-risk high-exposure nodes"],"title":"Weak Risk Resilience, Single-Point Dependency"},{"img":"https://images.unsplash.com/photo-1543286386-713bdd548da4?auto=format&fit=crop&w=1200&q=80","num":"Gut-Feel Decisions","desc":"Replenishment quantities based on gut feel, logistics mode chosen by intuition, supplier selection driven by personal preference. When a veteran employee leaves, critical supply chain knowledge walks out the door with them.","items":["AI replenishment recommendations: integrates forecast, inventory, and lead time distribution to auto-calculate optimal quantities","TCO modeling: computes full-chain total cost; recommends lowest TCO rather than lowest unit price","Knowledge retention: auto-records commitment vs actual performance, building a true supplier profile over time"],"title":"Gut-Feel Decisions, Lack of Data-Driven Insight"}]' WHERE id = 34;

-- ============================================================
